import React, { Component } from "react";
import "./App.css";

class Slider extends Component {
  constructor(props) {
    super(props);

    this.timeout = null;
  }
  timeout = setTimeout(clearTimeout(this.timeout), 5000);

  componentWillUnmount() {
    clearTimeout(this.timeout);
  }

  render() {
    return (
      <div className="divSlider">
        <img
          className="programmingIMG1"
          src="https://images.unsplash.com/photo-1587620962725-abab7fe55159?ixlib=rb-4.0.3&ixid=MnwxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8&auto=format&fit=crop&w=1631&q=80"
          alt="programmingPhoto1"
        />
        <img
          className="programmingIMG2"
          src="https://images.unsplash.com/photo-1587620962725-abab7fe55159?ixlib=rb-4.0.3&ixid=MnwxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8&auto=format&fit=crop&w=1631&q=80"
          alt="programmingPhoto1"
        />
      </div>
    );
  }
}
